#include "config_save.h"
#include "config.h"

UserConfigManager configManager;

void setup() {
  Serial.begin(115200);

  if (configManager.begin()) {
    UserConfig cfg = configManager.get();
    Serial.printf("生日: %d-%02d-%02d\n", cfg.birth_year, cfg.birth_month, cfg.birth_day);
  }

  // 修改并保存
  configManager.setBirthDate(1997, 5, 20);
  configManager.save();
}

void loop() {}
